var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"CANNON_ADMIN_NULL_NULL","text":{"KOREA":"<color=#ffd34c>입자 가속기 출력 최대.</color>","JPN":"<color=#ffd34c>粒子加速器、出力最大。</color>","ENG":"<color=#ffd34c>Particle accelerator at maximum output.</color>","TWN":"<color=#ffd34c>粒子加速器輸出最大化。</color>"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":null,"C":{"char_id":"CANNON_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"CANNON_ADMIN_NULL_NULL","text":{"KOREA":"<color=#ffd34c>냉각 과정을 배제하고 재포격합니다.</color>","JPN":"<color=#ffd34c>冷却過程を省き、再砲撃を行います。</color>","ENG":"<color=#ffd34c>Commencing fire without cooling.</color>","TWN":"<color=#ffd34c>排除冷卻程序，再度砲擊。</color>"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":null,"C":{"char_id":"CANNON_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ARTIL_ADMIN_CORRUPT_NULL","text":{"KOREA":"큭......! 내가 아는 화력이 아니잖아!","JPN":"くっ……！　私の記憶にある火力とは桁違いだ！","ENG":"Ugh! This isn't the firepower I know!","TWN":"唔……！這不是我所知道的火力！"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_CORRUPT_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"GSWORD_ADMIN_CORRUPT_NULL","text":{"KOREA":"리미터가 해제된 것 같아. 긴급 상황에서 기체가 손상되더라도 그 이상의 출력을 뽑아내는 거야.","JPN":"リミッターが解除されてるみたいね。緊急状況下で\\n機体の損傷を省みずに、規格外の出力を叩き出せる状態なの。","ENG":"Their limiters seems to have been removed. It lets them go into overdrive mode in emergencies, even if it damages their bodies.","TWN":"那好像解除了限制器。在緊急情況下機體就算破損，也會輸出更高的功率。"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":{"char_id":"ARTIL_ADMIN_CORRUPT_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_CORRUPT_NULL","face":"UNIT_HATE"}}}},{"id":"L16_1","type":"dialog","speaker":"GSWORD_ADMIN_CORRUPT_NULL","text":{"KOREA":"하지만 그러려면 하이브 컨트롤 이상의 권한이 있어야 할 텐데......","JPN":"でも、あれをやるにはハイブコントロール以上の\\n権限が必要なはず……","ENG":"But you'd need an access level beyond Hive Control itself to do that...","TWN":"但那不是需要高於巢穴控制系統的權限嗎……"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":{"char_id":"ARTIL_ADMIN_CORRUPT_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_CORRUPT_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"GSWORD_ADMIN_CORRUPT_NULL","text":{"KOREA":"대체 뭘 데리고 온 거야, 전대장?","JPN":"いったい何者を連れてきちゃったの？","ENG":"What the heck have you brought back with you, Commander?","TWN":"妳到底把什麼東西帶過來了，隊長？"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":{"char_id":"ARTIL_ADMIN_CORRUPT_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_CORRUPT_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"ARTIL_ADMIN_CORRUPT_NULL","text":{"KOREA":"그럼 설마, 저 기술자라는 놈이......!","JPN":"まさか、あのエンジニアを名乗った男が……！","ENG":"You mean that engineer pulled this trick?","TWN":"難道，那個叫技術員是……！"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":{"char_id":"ARTIL_ADMIN_CORRUPT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GSWORD_ADMIN_CORRUPT_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"GSWORD_ADMIN_CORRUPT_NULL","text":{"KOREA":"계속 싸우면 우리 애들 피해가 커져. 후퇴하자.","JPN":"このまま戦っても子どもたちの被害が増えるだけだわ。撤退しましょう。","ENG":"We'll take too many losses if we keep fighting. Let's fall back.","TWN":"繼續戰鬥的話，我們孩子的損失會更大，撤退吧。"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_CORRUPT_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"ARTIL_ADMIN_CORRUPT_NULL","text":{"KOREA":"나약한 소리 집어치워!","JPN":"甘ったれたことを言うな！","ENG":"Stop whining like a loser!","TWN":"不准說喪氣話！"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_CORRUPT_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"ARTIL_ADMIN_CORRUPT_NULL","text":{"KOREA":"저것들은 곧 죄다 멈출 거다!","JPN":"あんなモノ、今にすべて停止させてやる！","ENG":"They will all stop soon!","TWN":"他們馬上就會停止運轉的！"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_CORRUPT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"ARTIL_ADMIN_CORRUPT_NULL","text":{"KOREA":"전 병력, 고철들은 무시하고 방주로 돌격해!","JPN":"クズ鉄どもには構うな。総員、箱舟めがけて突撃せよ！","ENG":"All troops, ignore the junk machines and charge to the Ark!","TWN":"所有兵力，無視那些廢鐵，朝著方舟突擊！"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_CORRUPT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"ARTIL_ADMIN_CORRUPT_NULL","text":{"KOREA":"무슨 수를 쓰더라도 안에 있는 놈들을 모조리 죽여 버려!","JPN":"中にいる連中を皆殺しにしてやれ！　どんな手を使ってでもだ！","ENG":"Kill everyone inside, no matter what it takes!","TWN":"不論使用什麼方法，把裡面的傢伙全部殺光！"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_CORRUPT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"ARTIL_ADMIN_CORRUPT_NULL","text":{"KOREA":"네놈들은 어차피 다 뒈져도 상관없는 것들이야! 꾸물거리는 놈은 내가 직접 처형한다!","JPN":"貴様たちは全員玉砕して構わない捨て石どもだ！\\nモタモタしてる奴には私が直接手を下す！","ENG":"You're all useless to me anyway! If you hesitate, I'll kill you myself!","TWN":"反正你們這些笨蛋就算下地獄也沒差！誰敢拖拖拉拉的，我就會親自處刑他！"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_CORRUPT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"GSWORD_ADMIN_CORRUPT_NULL","text":{"KOREA":"썩을...... 화약 냄새만 맡으면 눈이 돌아가서는.","JPN":"クソ軍人……火薬の臭いに触発されちゃってるわね。","ENG":"Oh, gosh... She just loses it whenever she smells gunpowder.","TWN":"真是的……一聞到火藥味就變得這麼瘋狂。"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_CORRUPT_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"GSWORD_ADMIN_CORRUPT_NULL","text":{"KOREA":"포대에 화력 지원 요청해! 다들 돌격한다!","JPN":"砲台に火力支援を要請しなさい！　みんなで突撃するわよ！","ENG":"Ask the artillery for fire support! We're going to charge!","TWN":"請求炮臺火力支援！全員突擊！"},"stage":{"bg":"COUNTERSIDE_GRAVE","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_CORRUPT_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};